app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally
  const status = err.status || 500;
  res.status(status).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error' // Never expose stack traces in prod
      : err.message
  });
});
```

#### 5. No CORS Policy
Without explicit CORS configuration, cross-origin behavior is left to browser defaults:
```js
