app.get('/health', (req, res) => {
  // Avoid leaking server internals — keep health responses minimal
  res.json({ status: 'ok' });
});

app.get('/users', (req, res, next) => {
  try {
    // TODO: Replace with actual DB call; never expose sensitive fields (e.g., passwords, tokens)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];
    res.json(users);
  } catch (err) {
    next(err); // Forward errors to the global error handler
  }
});

// ─── 4. 404 Handler ──────────────────────────────────────────────────────────
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ─── 5. Global Error Handler ─────────────────────────────────────────────────
// Must have exactly 4 arguments for Express to treat it as error middleware
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Log internally — never send raw error details to the client
  console.error(`[ERROR] ${req.method} ${req.path}:`, err);

  const status = err.status || err.statusCode || 500;
  res.status(status).json({
    error: status < 500 ? err.message : 'Internal server error',
  });
});

// ─── 6. Graceful Shutdown ─────────────────────────────────────────────────────
const server = app.listen(3000, () => {
  console.log('Server running on port 3000');
});

const shutdown = (signal) => {
  console.log(`${signal} received. Shutting down gracefully...`);
  server.close(() => {
    console.log('Server closed.');
    process.exit(0);
  });
};

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

module.exports = app;
